<template>
  <div style="padding: 100px 0 20px 0">
    <div class="panel" :class="{ blur: theme.blur }">
      <div
        class="bgimg"
        :style="{
          backgroundImage:
            'url(' + require('@/img/minecraft/background.webp') + ')',
        }"
      >
        <img src="@/img/minecraft/logo.webp" alt="" class="mclogo" />
      </div>
      <div
        class="pageText"
        v-html="format"
        style="padding: 0 40px 20px 40px"
      ></div>
    </div>
  </div>
</template>

<script>
import showdown from "showdown";
import Prism from "prismjs";
import "@/css/prism.css";
import { getDoc } from "@/api/ajax";
import { confs } from "@/config.js";
export default {
  name: "mcdoc",
  data: () => {
    return {
      format: "",
    };
  },
  props: ["theme"],
  mounted() {
    this.getContent();
  },
  methods: {
    getContent() {
      //获取文档
      getDoc("minecraft", (res) => {
        let md = res;
        //md生成html
        let converter = new showdown.Converter();
        this.format = converter.makeHtml(md);
        this.$nextTick(() => {
          //code样式添加
          for (
            let i = 0;
            i < document.getElementsByTagName("pre").length;
            i++
          ) {
            document.getElementsByTagName("pre")[i].className =
              "language-js line-numbers";
          }
          Prism.highlightAll();
          //图片地址重定向
          for (
            let i = 0;
            i < document.getElementsByTagName("img").length;
            i++
          ) {
            let img = document.getElementsByTagName("img")[i];
            if (img.alt.includes("md")) {
              console.log(img.src.split("/")[img.src.split("/").length - 1]);
              document.getElementsByTagName("img")[i].src =
                confs().server +
                "get/doc/minecraft/" +
                img.src.split("/")[img.src.split("/").length - 1];
            }
          }
        });
      });
    },
  },
};
</script>

