<template>
  <div id="column" :class="{ blur: theme.blur }">
    <a :href="'/blog/page/' + column.noid" target="_blank">
      <el-container class="blogColumn">
        <el-aside width="100px">
          <table
            style="width: 100%; height: 100px"
            cellpadding="0"
            cellspacing="0"
          >
            <tr>
              <td style="text-align: center">
                <el-image
                  :src="column.img"
                  style="padding: 10px; max-width: 80px; max-height: 80px"
                  alt=""
                  fit="scale-down"
                >
                  <span slot="error" style="color: #606266">
                    <i
                      class="far fa-image"
                      style="font-weight: 300; font-size: 50px"
                    ></i>
                  </span>
                </el-image>
              </td>
            </tr>
          </table>
        </el-aside>
        <el-main>
          <div>
            <el-col :span="24" style="font-size: 24px"
              ><b>{{ column.title }}</b></el-col
            >
          </div>
          <div>
            <el-col :span="24" style="font-size: 14px; line-height: 28px">{{
              column.subtitle
            }}</el-col>
          </div>
          <div>
            <el-row style="font-size: 14px">
              <el-col :span="12"
                ><i class="el-icon-user-solid" style="margin-right: 4px"></i
                >{{ column.author }}</el-col
              >
              <el-col :span="12" style="text-align: right">{{
                parseTime(column.date)
              }}</el-col>
            </el-row>
          </div>
        </el-main>
      </el-container>
    </a>
  </div>
</template>
<script>
export default {
  name: "column",
  data: function () {
    return {};
  },
  props: ["column", "theme"],
  methods: {
    parseTime(value) {
      let date = new Date();
      date.setTime(value);
      let year = date.getFullYear();
      let month = date.getMonth();
      let day = date.getDate();
      return year + "年" + (month + 1) + "月" + day + "日";
    },
  },
};
</script>
