var CryptoJS = require("crypto-js")
//读取Cookie
export function getCookie(cname) {
    var name = cname + "=";
    var ca = document.cookie.split(";");
    for (var i = 0; i < ca.length; i++) {
        var c = ca[i].trim();
        if (c.indexOf(name) == 0) {
            return c.substring(name.length, c.length);
        }
    }
    return null;
}
//写入Cookie
export function writeCookie(label, value, expires) {
    if (typeof (expires) == "undefined") {
        let d = new Date()
        d.setTime(d.getTime() + 90 * 24 * 3600 * 1000)
        expires = d.toUTCString()
    }
    document.cookie = label + "=" + value + "; expires=" + expires + "; path=/";
}
//清除Cookie
export function clearCookie(label) {
    document.cookie = label + "=; expires=Thu, 01 Jan 1970 00:00:00 GMT; path=/";
}
//SHA256加密
export function sha256(value, n) {
    let respond = value
    for (let i = 0; i < n; i++) {
        respond = CryptoJS.SHA256(respond).toString()
    }
    return respond
}
//SHA512加密
export function sha512(value, n) {
    let respond = value
    for (let i = 0; i < n; i++) {
        respond = CryptoJS.SHA512(respond).toString()
    }
    return respond
}