    >
      <el-row>
        <el-col :sm="8" :xs="12">
          <table
            style="width: 100%; height: 80px"
            cellpadding="0"
            cellspacing="0"
          >
            <tr>
              <td>
                <i
                  class="fas fa-bars"
                  style="
                    font-size: 24px;
                    text-align: right;
