                    cursor: pointer;
                  "
                  @click="$emit('drawerAppear')"
                />
              </td>
              <td style="height: 80px; width: 60px">
                <img
                  width="60px"
                  height="60px"
                  src="@/img/logo-white.svg"
                  alt=""
                />
              </td>
              <td class="pageTitle">
                <span>{{ pageTitle }}</span>
              </td>
            </tr>
          </table>
        </el-col>
        <el-col :sm="8" :xs="0" class="hidden-xs-only">
          <table
            style="width: 100%; height: 80px"
            cellpadding="0"
            cellspacing="0"
          >
            <tr>
              <td>
                <el-input
                  prefix-icon="el-icon-search"
                  v-model="search.input"
                  :placeholder="search.placeholder"
                  @keyup.enter.native="searchBlog"
                ></el-input>
              </td>
            </tr>
          </table>
        </el-col>
        <el-col :sm="8" :xs="12" class="rightMenu">
          <table
            style="width: 100%; height: 80px"
            cellpadding="0"
            cellspacing="0"
          >
            <tr>
              <td>
                <i
                  @click="searchTopStyle.top = '0px'"
                  class="fas fa-search hidden-sm-and-up"
                  style="margin-right: 10px"
                />
                <span class="rightMenuLink">
                  <a :href="homePage" target="_blank">首页</a></span
                >
                <span class="rightMenuLink" @click="$emit('viewThemeWindow')"
                  >个性化</span
                >
              </td>
              <td>
                <el-popover
                  placement="bottom"
                  width="250"
                  trigger="hover"
                  :popper-class="theme.blur ? 'blur' : null"
                >
                  <img
                    :src="user.avatar || require('@/img/login.svg')"
                    alt=""
                    slot="reference"
                    style="
                      width: 40px;
                      height: 40px;
                      border: rgba(255, 255, 255, 0.75) 2px solid;
                      border-radius: 40px;
                      box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
                      background-color: rgba(0, 0, 0, 0.05);
                    "
                  />
                  <div v-if="login">
                    <div style="text-align: center">
                      <img
                        :src="user.avatar || require('@/img/login.svg')"
                        alt=""
                        style="
                          width: 60px;
                          height: 60px;
                          border: rgba(0, 0, 0, 0.2) 2px solid;
                          border-radius: 60px;
                          box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
                          background-color: rgba(0, 0, 0, 0.1);
                        "
                      />
                    </div>
                    <div
                      style="
                        padding: 0 20px;
                        text-align: center;
                        white-space: nowrap;
