                      "
                    >
                      <div
                        style="
                          font-size: 22px;
                          font-weight: bold;
                          text-overflow: ellipsis;
                          overflow: hidden;
                        "
                      >
                        {{ user.name || "Loading……" }}
                      </div>
                      <div
                        style="
                          text-overflow: ellipsis;
                          overflow: hidden;
                          height: 22px;
                        "
                      >
                        {{ user.signature || "Loading……" }}
                      </div>
                      <div
                        style="
                          font-weight: bold;
                          text-overflow: ellipsis;
                          overflow: hidden;
                        "
                      >
                        <i class="fa fa-user fa-fw"></i>
                        {{ getRoleName(user.role) }}
                      </div>
                      <div style="padding: 10px 0">
                        <el-button size="mini" onclick="window.open('/user/my')"
                          ><i class="fas fa-home fa-fw"></i
                          >&nbsp;个人空间</el-button
                        >
                        <el-button size="mini"
                          ><i class="fas fa-comment-dots fa-fw"></i
