                        margin: 10px 0 20px 0;
                      "
                    >
                      登录以使用更多功能
                    </div>
                    <div style="margin: 20px 0 10px 0">
                      <el-button @click="$emit('login')"
                        ><i class="fas fa-user fa-fw"></i>&nbsp;登录</el-button
                      >
                    </div>
                  </div>
                </el-popover>
              </td>
            </tr>
          </table>
        </el-col>
      </el-row>
      <div
        class="search-top"
        :style="{ top: searchTopStyle.top, backgroundColor: theme.color }"
      >
        <table
          style="width: 100%; height: 80px; padding: 0 20px"
          cellpadding="0"
          cellspacing="0"
        >
          <tr>
            <td>
              <el-input
                prefix-icon="el-icon-search"
                v-model="search.input"
                :placeholder="search.placeholder"
                @keyup.enter.native="searchBlog"
              >
                <el-button
                  slot="prepend"
                  icon="el-icon-close"
                  @click="searchTopStyle.top = '-80px'"
                ></el-button>
                <el-button slot="append" icon="el-icon-search"></el-button>
              </el-input>
            </td>
