      </div>
    </div>
  </div>
</template>

<script>
import { getExcerpt } from "@/api/ajax.js";
import { clearCookie } from "@/api/function.js";
export default {
  name: "topBar",
  data: function () {
    return {
      search: {
        input: "",
        placeholder: "search",
      },
      searchTopStyle: {
        top: "-80px",
      },
      homePage: "/blog",
    };
  },
  props: ["pageTitle", "user", "theme", "login"],
  created() {
    this.getSearchPlaceholder();
  },
  methods: {
    getSearchPlaceholder() {
      getExcerpt((returns) => {
        this.search.placeholder = returns.data;
      });
      let url = decodeURI(window.location);
      let search = null;
      if (url.indexOf("?s=") != -1) {
        search = url.slice(url.indexOf("?s=") + 3);
      }
      this.search.input = search;
    },
    getRoleName(r) {
      switch (r) {
        case 1:
          return "站务";
        case 2:
          return "站务";
        case 3:
          return "管理员";
        case 4:
          return "普通用户";
        case 5:
          return "测试用户";
        default:
          return "No Type ";
      }
    },
    logout() {
      this.$confirm("这将在本计算机上退出您的账号", "退出登录", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        modal: false,
        customClass: this.theme.blur ? "blur" : null,
        type: "info",
      })
        .then(() => {
          clearCookie("user");
          clearCookie("cookie");
          this.$message.warning("已登出");
          setTimeout(() => {
            location.reload();
          }, 1000);
        })
        .catch(() => {});
    },
    searchBlog() {
      if (this.search.input) {
        window.location = "/blog/?s=" + this.search.input;
      } else {
        window.location = "/blog";
      }
    },
  },
};
</script>

