<template>
  <div
    id="register"
    v-loading.fullscreen="loading"
    style="padding-top: 13vh; margin: 0 auto; max-width: 900px"
  >
    <div class="panel" :class="{ blur: theme.blur }">
      <div style="color: #636363; font-size: 20px">
        <img src="@/img/logo.svg" style="height: 30px; width: 30px" alt="" />
        <span style="position: relative; bottom: 6px; left: 6px">Qisato</span>
      </div>
      <div style="font-size: 26px; line-height: 46px">创建您的QNV账号</div>
      <div style="display: flex; margin-top: 20px; font-size: 14px">
        <div style="flex: 5">
          <span>昵称</span>
          <span
            style="float: right"
            :style="{ color: nameMessage.color }"
            v-html="nameMessage.text"
          ></span>
          <el-input
            v-model="name"
            @input="nameMessage.text = null"
            @blur="checkName"
            size="small"
          />
          <span>登录名</span>
          <span
            style="float: right"
            :style="{ color: loginMessage.color }"
            v-html="loginMessage.text"
          ></span>
          <el-input
            v-model="login"
            @input="loginMessage.text = null"
            @blur="checkLogin"
            size="small"
          />
          <div style="display: flex" class="hidden-xs-only">
            <div style="flex: 1; padding-right: 5px">
              <span>电子邮箱</span>
              <span
                style="float: right"
                :style="{ color: mailMessage.color }"
                v-html="mailMessage.text"
              ></span>
              <el-input
                v-model="mail"
                @input="mailMessage.text = null"
                @blur="checkMail"
                size="small"
              />
            </div>
            <div style="flex: 1; padding-left: 5px">
              <span>验证码</span>
              <span
                style="float: right"
                :style="{ color: mailvcodeMessage.color }"
                v-html="mailvcodeMessage.text"
              ></span>
              <el-input
                v-model="mailvcode"
                @input="mailvcodeMessage.text = null"
                @blur="checkMailVcode"
                onkeyup="this.value = this.value.toUpperCase()"
                size="small"
                maxlength="6"
              >
                <el-button slot="append" @click="sendMailVcode"
                  >发送验证码</el-button
                >
              </el-input>
            </div>
          </div>
          <span class="hidden-sm-and-up">
            <span>电子邮箱</span>
            <span
              style="float: right"
              :style="{ color: mailMessage.color }"
              v-html="mailMessage.text"
            ></span>
            <el-input
              v-model="mail"
              @input="mailMessage.text = null"
              @blur="checkMail"
              size="small"
            />
            <span>验证码</span>
            <span
              style="float: right"
              :style="{ color: mailvcodeMessage.color }"
              v-html="mailvcodeMessage.text"
            ></span>
            <el-input
              v-model="mailvcode"
              @input="mailvcodeMessage.text = null"
              onkeyup="this.value = this.value.toUpperCase()"
              @blur="checkMailVcode"
              size="small"
              maxlength="6"
            >
              <el-button slot="append" @click="sendMailVcode"
                >发送验证码</el-button
              >
            </el-input>
          </span>
          <span>密码</span>
          <span
            style="float: right"
            :style="{ color: passwdMessage.color }"
            v-html="passwdMessage.text"
          ></span>
          <el-input
            v-model="passwd"
            @input="checkPasswd"
            show-password
            size="small"
          />
          <span>再次输入密码</span>
          <span
            style="float: right"
            :style="{ color: passwdNextMessage.color }"
            v-html="passwdNextMessage.text"
          ></span>
          <el-input
            v-model="passwdNext"
            @input="passwdNextMessage.text = null"
            @blur="checkPasswdNext"
            show-password
            size="small"
          />
          <span
            style="
              margin: 10px 0 5px 0;
              display: inline-block;
              color: #409eff;
              cursor: pointer;
            "
            @click="$emit('login', true)"
            >登录现有账号</span
          >
          <span style="float: right">
            <el-checkbox>同意</el-checkbox>
            <span
              style="cursor: pointer; margin-right: 5px"
              @click="userAgreementDialog = true"
              >《猫夏账号用户协议》</span
            >
            <el-button @click="next" type="primary">下一步</el-button>
          </span>
          <br />
          <a
            href="/register/email"
            target="_blank"
            style="margin: 5px 0 10px 0; display: inline-block; color: #409eff"
            >邮件申请注册入口</a
          >
        </div>
        <div
          style="flex: 4; text-align: center; font-size: 18px; color: #636363"
          class="hidden-xs-only"
        >
          <img src="@/img/register.svg" style="width: 250px" alt="" />
          <br />
          <br />
          注册账号，即可使用所有功能
        </div>
      </div>
    </div>
    <div
      style="padding: 0px 20px 50px 20px; font-size: 14px"
      :style="{
        color: theme.background ? '#fff' : '#37474f',
        textShadow: theme.background ? '0 0 5px rgba(0, 0, 0, 0.5)' : null,
      }"
    >
      <span>
        <el-select
          v-model="language"
          :style="{ float: language == 'ar-sa' ? 'right' : 'left' }"
          size="mini"
          placeholder="选择语言"
        >
          <el-option
            v-for="item in list"
            :key="'language' + item.value"
            :label="item.label"
            :value="item.value"
          >
          </el-option>
        </el-select>
      </span>
      <span style="display: inline-block; margin: 10px"> </span>
      <span style="float: right; display: inline-block; margin: 10px">
        <span style="cursor: pointer">帮助</span>
        &nbsp;&nbsp;
        <span style="cursor: pointer" @click="userAgreementDialog = true"
          >猫夏账号用户协议</span
        >
      </span>
    </div>
    <el-dialog
      :modal="false"
      title="图片验证码"
      width="500px"
      top="18vh"
      :visible.sync="vcodeDialog"
      :append-to-body="true"
      :close-on-click-modal="false"
      :custom-class="theme.blur ? 'blur' : null"
      style="user-select: none"
      :destroy-on-close="true"
    >
      <div>请计算下列问题并输入运算结果</div>
      <vcode
        type="4"
        ref="vcode"
        style="
          width: 300px;
          height: 200px;
          margin: 20px auto;
          border: #909090 2px dashed;
        "
      />
      <el-input
        style="margin: 20px 0"
        v-model="vcodeInput"
        :clearable="true"
        size="small"
      />
      <div style="text-align: right">
        <el-button size="small" type="primary" @click="verifyVcode"
          >验证</el-button
        >
      </div>
      <div></div>
    </el-dialog>
    <el-dialog
      :modal="false"
      title="猫夏账号用户协议"
      width="80vw"
      :visible.sync="userAgreementDialog"
      :append-to-body="true"
      :custom-class="theme.blur ? 'blur' : null"
      :destroy-on-close="true"
    >
      <user-agreement style="height: 60vh" />
    </el-dialog>
  </div>
</template>
<script>
import vcode from "./components/vcode.vue";
import userAgreement from "./components/userAgreementCOM.vue";
import {
  checkRegUserLogin,
  checkRegUserMail,
  sendRegUserVcode,
  verifyRegVcode,
  registerUser,
} from "@/api/ajax.js";
import { sha256 } from "@/api/function";
export default {
  name: "register",
  components: {
    vcode,
    userAgreement,
  },
  props: ["theme"],
  data: () => {
    return {
      loading: false,
      vcodeDialog: false,
      userAgreementDialog: false,
      vcodeInput: null,
      language: "zh-cn",
      list: [{ value: "zh-cn", label: "简体中文" }],
      name: null,
      login: null,
      mail: null,
      mailvcode: null,
      passwd: null,
      passwdNext: null,
      nameMessage: {
        color: null,
        text: null,
        check: false,
      },
      loginMessage: {
        color: null,
        text: null,
        check: false,
      },
      mailMessage: {
        color: null,
        text: null,
        check: false,
      },
      mailvcodeMessage: {
        color: null,
        text: null,
        check: false,
      },
      passwdMessage: {
        color: null,
        text: null,
      },
      passwdNextMessage: {
        color: null,
        text: null,
        check: false,
      },
    };
  },
  methods: {
    checkName() {
      if (this.name) {
        this.nameMessage.check = true;
      } else {
        this.nameMessage.check = false;
      }
    },
    checkLogin() {
      let login = this.login;
      let verify = /^[a-zA-Z][a-zA-Z0-9_]{0,31}$/g;
      if (login) {
        if (verify.test(login) == true) {
          this.loginMessage.color = "#FFB300";
          this.loginMessage.text = "检查中……";
          checkRegUserLogin(login, (res) => {
            if (res.code == "200") {
              this.loginMessage.color = "#4CAF50";
              this.loginMessage.text = '<i class="fas fa-check-circle"></i>';
              this.loginMessage.check = true;
            } else {
              this.loginMessage.color = "#F56C6C";
              this.loginMessage.text = "登录名已被占用";
              this.loginMessage.check = false;
            }
          });
        } else {
          this.loginMessage.color = "#F56C6C";
          if (login.length < 32) {
            this.loginMessage.text =
              "登录名仅可包括字母数字下划线且不能以数字开头";
          } else {
            this.loginMessage.text = "登录名最多32个字符";
          }
          this.loginMessage.check = false;
        }
      }
    },
    checkMail() {
      let mail = this.mail;
      let verify = /^\w+([-+.]\w+)*@\w+([-.]\w+)*\.\w+([-.]\w+)*$/g;
      if (mail) {
        if (verify.test(mail) == true) {
          this.mailMessage.color = "#FFB300";
          this.mailMessage.text = "检查中……";
          checkRegUserMail(mail, (res) => {
            if (res.code == "200") {
              this.mailMessage.color = "#4CAF50";
              this.mailMessage.text = '<i class="fas fa-check-circle"></i>';
              this.mailMessage.check = true;
            } else {
              this.mailMessage.color = "#F56C6C";
              this.mailMessage.text = "该邮箱已被占用";
              this.mailMessage.check = false;
            }
          });
        } else {
          this.mailMessage.color = "#F56C6C";
          this.mailMessage.text = "邮箱格式不正确";
          this.mailMessage.check = false;
        }
      }
    },
    sendMailVcode() {
      if (this.mail) {
        sendRegUserVcode(this.mail, (res) => {
          if (res.code == "200") {
            this.$message.success("验证码已发送");
          } else if (res.code == "202") {
            this.$message.error("该邮箱已被占用");
          } else if (res.code == "204") {
            this.$message.info("请在" + res.data + "秒后再试");
          } else {
            this.$message.error("验证码发送失败");
          }
        });
      } else {
        this.$message.error("请输入正确的邮箱");
      }
    },
    checkMailVcode() {
      if (this.mailvcode && this.mailMessage.check) {
        this.mailvcode = this.mailvcode.toUpperCase();
        let vcode = sha256(this.mailvcode, 16);
        verifyRegVcode(this.mail, vcode, (res) => {
          if (res.code == "200") {
            this.mailvcodeMessage.color = "#4CAF50";
            this.mailvcodeMessage.text = '<i class="fas fa-check-circle"></i>';
            this.mailvcodeMessage.check = true;
          } else if (res.code == 203) {
            this.mailvcodeMessage.color = "#F56C6C";
            this.mailvcodeMessage.text = "验证码失效";
            this.mailvcodeMessage.check = false;
          } else {
            this.mailvcodeMessage.color = "#F56C6C";
            this.mailvcodeMessage.text = "验证码不正确";
            this.mailvcodeMessage.check = false;
          }
        });
      } else {
        this.mailvcodeMessage.check = false;
      }
    },
    checkPasswd() {
      this.passwdNextMessage.text = null;
      this.passwdNext = null;
      if (this.passwd.length < 6) {
        this.passwdMessage.text = null;
        this.passwdMessage.check = false;
      } else {
        if (this.passwd.length < 8) {
          this.passwdMessage.color = "#F56C6C";
          this.passwdMessage.text =
            "<i class='fas fa-key'></i> 密码长度较短，不建议使用";
        } else {
          let l = false,
            s1 = false,
            s2 = false,
            s3 = false,
            s4 = false;
          if (this.passwd.length >= 12) {
            l = true;
          }
          for (let i = 0; i < this.passwd.length; i++) {
            let t = 0;
            if (this.passwd[i].search(/[0-9]/) != -1) {
              s1 = true;
            } else {
              t++;
            }
            if (this.passwd[i].search(/[a-z]/) != -1) {
              s2 = true;
            } else {
              t++;
            }
            if (this.passwd[i].search(/[A-Z]/) != -1) {
              s3 = true;
            } else {
              t++;
            }
            if (t == 3) {
              s4 = true;
            }
          }
          console.log(s4);
          if (s1 && s2 && s3 && s4) {
            if (l) {
              this.passwdMessage.color = "#00897B";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码强度非常强";
            } else {
              this.passwdMessage.color = "#43A047";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码强度很强";
            }
          } else if (
            (s2 && s3 && s4) ||
            (s1 && s3 && s4) ||
            (s1 && s2 && s4) ||
            (s1 && s2 && s3)
          ) {
            if (l) {
              this.passwdMessage.color = "#C0CA33";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码强度较强";
            } else {
              this.passwdMessage.color = "#FBC02D";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码强度适中";
            }
          } else if (
            (s1 && s2) ||
            (s1 && s3) ||
            (s1 && s4) ||
            (s2 && s3) ||
            (s2 && s4) ||
            (s3 && s4)
          ) {
            if (l) {
              this.passwdMessage.color = "#FBC02D";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码强度适中";
            } else {
              this.passwdMessage.color = "#FB8C00";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码强度较弱";
            }
          } else {
            if (l) {
              this.passwdMessage.color = "#F4511E";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码较为单一";
            } else {
              this.passwdMessage.color = "#F4511E";
              this.passwdMessage.text =
                "<i class='fas fa-key'></i> 密码强度很弱";
            }
          }
        }
        this.passwdMessage.check = true;
      }
    },
    checkPasswdNext() {
      if (this.passwd == this.passwdNext) {
        this.passwdNextMessage.check = true;
      } else {
        this.passwdNextMessage.color = "#F56C6C";
        this.passwdNextMessage.text = "两次密码输入不一致";
        this.passwdNextMessage.check = false;
      }
    },
    //下一步
    next() {
      if (
        this.name &&
        this.login &&
        this.mail &&
        this.mailvcode &&
        this.passwd &&
        this.passwdNext
      ) {
        if (
          this.nameMessage.check &&
          this.loginMessage.check &&
          this.mailMessage.check &&
          this.mailvcodeMessage.check &&
          this.passwdMessage.check &&
          this.passwdNextMessage.check
        ) {
          this.vcodeDialog = true;
        } else {
          let message = "请检查";
          let messageArr = [];
          if (!this.nameMessage.check) {
            messageArr.push("昵称");
          }
          if (!this.loginMessage.check) {
            messageArr.push("登录名");
          }
          if (!this.mailMessage.check) {
            messageArr.push("邮箱");
          }
          if (!this.mailvcodeMessage.check) {
            messageArr.push("验证码");
          }
          if (!this.passwdMessage.check) {
            messageArr.push("密码");
          }
          if (!this.passwdNextMessage.check) {
            messageArr.push("第二次输入密码");
          }
          for (let i = 0; i < messageArr.length; i++) {
            message = message + messageArr[i] + "、";
          }
          message = message.slice(0, message.length - 1);
          this.$message.error(message);
        }
      } else {
        if (!this.name) {
          this.nameMessage.color = "#F56C6C";
          this.nameMessage.text = "请输入昵称";
        }
        if (!this.login) {
          this.loginMessage.color = "#F56C6C";
          this.loginMessage.text = "请输入登录名";
        }
        if (!this.mail) {
          this.mailMessage.color = "#F56C6C";
          this.mailMessage.text = "请输入邮箱";
        }
        if (!this.mailvcode) {
          this.mailvcodeMessage.color = "#F56C6C";
          this.mailvcodeMessage.text = "请输入验证码";
        }
        if (!this.passwd) {
          this.passwdMessage.color = "#F56C6C";
          this.passwdMessage.text = "请输入密码";
        }
        if (!this.passwdNext) {
          this.passwdNextMessage.color = "#F56C6C";
          this.passwdNextMessage.text = "请再次输入密码";
        }
      }
    },
    //验证验证码
    verifyVcode() {
      let result = this.$refs.vcode.verifyVcode(this.vcodeInput);
      if (result == true) {
        this.register();
      } else {
        this.$message.error("验证码错误");
      }
    },
    //注册
    register() {
      this.loading = true;
      let reg = {
        name: this.name,
        login: this.login,
        mail: this.mail,
        mailvcode: sha256(this.mailvcode, 16),
        passwd: sha256(this.passwd, 16),
      };
      registerUser(reg, (res) => {
        this.loading = false;
        if (res.code == "200") {
          //注册成功
          this.$message.success("注册成功");
          setTimeout(() => {
            window.location = "/login";
          }, 1000);
        } else {
          //注册失败
          this.$message.error("注册失败");
        }
      });
    },
  },
};
</script>
<style scoped>
.panel {
  margin: 20px 20px 0 20px;
  box-shadow: 0 0 2px rgba(0, 0, 0, 0.25);
  border-radius: 6px;
  background-color: rgba(255, 255, 255, 0.95);
  padding: 40px 40px;
}
#register >>> .el-input {
  margin: 10px 0;
}
#register >>> .el-input__inner {
  backdrop-filter: blur(24px);
}
</style>