<template>
  <div id="blog">
    <el-container>
      <el-main style="padding: 100px 12px 0 12px">
        <el-skeleton
          :rows="8"
          :loading="loading"
          animated
          style="opacity: 0.8"
        />
        <div
          v-if="lists.length > 0 && search"
          style="font-size: 26px; padding: 0 20px 20px 20px"
          :style="{
            color: theme.background ? '#fff' : 'inherit',
            textShadow: theme.background ? '0 0 5px rgba(0, 0, 0, 0.5)' : null,
          }"
        >
          <span style="font-weight: bold">{{ search }}</span>
          的搜索结果：
        </div>
        <blog-column
          v-for="column in lists"
          :key="column.noid"
          :column="column"
          :theme="theme"
        />
        <div
          v-if="lists.length == 0 && search"
          :class="{ blur: theme.blur && theme.background }"
          :style="{
            backgroundColor: theme.background
              ? 'rgba(255, 255, 255, 0.95)'
              : '#0000',
            boxShadow: theme.background ? '0 0 2px rgba(0, 0, 0, 0.2)' : 'none',
          }"
          style="border-radius: 6px"
        >
          <div style="padding: 30px; font-size: 16px">
            抱歉没有找到与
            <span style="color: #c00">{{ search }}</span>
            相关的内容。
          </div>
          <div
            style="
              font-size: 14px;
              padding: 0 30px 30px 30px;
              line-height: 30px;
            "
          >
            <span style="color: #868686">温馨提示：</span><br />
            请检查您的输入是否正确<br />
            或者我们没有这篇文章<br />
            如有任何意见或建议，请及时反馈给我们<br />
          </div>
        </div>
      </el-main>
      <el-aside class="hidden-xs-only" width="274px">
        <side-bar
          :user="user"
          :theme="theme"
          :menu="menu"
          :starButton="false"
          :login="login"
        />
      </el-aside>
    </el-container>
  </div>
</template>
<script>
import blogColumn from "./components/blogColumn.vue";
import sideBar from "./components/sideBar.vue";
import { getBlogList } from "@/api/ajax.js";
export default {
  name: "blog",
  components: {
    blogColumn,
    sideBar,
  },
  data: function () {
    return {
      loading: true,
      lists: [],
      search: null,
      menu: {
        userActionMenuPanel: [
          //建议：分两组，每组两个
          {
            group: "0",
            list: [
              {
                title: "写文章",
                path: "/blog/edit",
                icon: "fas fa-edit",
              },
              {
                title: "传照片",
                path: "",
                icon: "fas fa-image",
              },
            ],
          },
          {
            group: "1",
            list: [
              {
                title: "个人主页",
                path: "/user/my",
                icon: "fas fa-user",
              },
              {
                title: "创作中心",
                path: "",
                icon: "fas fa-paper-plane",
              },
            ],
          },
        ],
        userActionMenuList: [
          {
            title: "我的收藏",
            path: "",
            icon: "fas fa-bookmark fa-fw",
          },
          {
            title: "我的关注",
            path: "",
            icon: "fas fa-star fa-fw",
          },
          {
            title: "我的相册",
            path: "",
            icon: "fas fa-images fa-fw",
          },
          {
            title: "个人资料",
            path: "",
            icon: "fas fa-child fa-fw",
          },
        ],
      },
    };
  },
  props: ["user", "theme", "login"],
  created() {
    this.getContent();
  },
  methods: {
    getContent() {
      let url = decodeURI(window.location);
      if (url.indexOf("?s=") != -1) {
        this.search = url.slice(url.indexOf("?s=") + 3);
      }
      getBlogList(this.search, null, (returns) => {
        this.lists = returns.data.reverse();
        this.loading = false;
        document.documentElement.scrollTop = 0;
        document.getElementById("sideBar").scrollTop = 0;
      });
    },
  },
};
</script>
<style scoped>
#blog /deep/ .el-container {
  max-width: 1100px;
  margin: 0 auto;
}
</style>
