            >
              <i class="fas fa-check-square fa-fw"></i>
              发布
            </el-button>
          </div>
        </div>
      </div>
      <div style="display: flex; height: calc(100% - 152px)">
        <div style="width: 50%; font-size: 0">
          <div style="display: flex; height: calc(100% - 22px)">
            <div class="edit-input-line-number">
              <div
                style="position: relative"
                :style="{ top: 0 - textScroll + 'px' }"
              >
                <div
                  v-for="(number, i) in allrow"
                  :key="'lnum' + i"
                  style="padding: 0 6px"
                  :style="{
                    color: number == row ? '#435d81' : '#aab1b9',
                    backgroundColor: number == row ? '#00b7ff20' : '#0000',
                  }"
                >
                  {{ number }}
                </div>
              </div>
            </div>
            <div style="flex: 1">
              <textarea
