              height: 20px;
              border: 1px solid #dcdfe6;
              font-size: 12px;
              line-height: 20px;
              padding: 0 10px;
              color: #666666;
              white-space: nowrap;
            "
          >
            <span>
              <el-popover
                placement="top"
                trigger="manual"
                v-model="selectImg"
                :popper-class="theme.blur ? 'blur' : null"
                @show="selectPopover(0)"
                @hide="selectPopover(1)"
              >
                <span
                  slot="reference"
                  style="cursor: pointer"
                  @click="
                    selectImg = !selectImg;
                    avatarImg = false;
                  "
                >
                  <i class="fas fa-file-image fa-fw"></i>
                  添加图片
                </span>
                <div style="height: 500px; width: 600px">
                  <span
                    @click="selectImg = false"
                    style="
                      position: absolute;
                      top: 4px;
                      right: 4px;
                      padding: 0 8px;
                      font-size: 20px;
                      cursor: pointer;
