                trigger="click"
                :popper-class="theme.blur ? 'blur' : null"
              >
                <i
                  slot="reference"
                  class="fas fa-info-circle fa-fw"
                  style="cursor: pointer"
                ></i>
                <div style="padding: 10px; width: 550px">
                  <el-tabs v-model="infoTab">
                    <el-tab-pane label="Markdown" name="0">
                      <md-pedia />
                    </el-tab-pane>
                    <el-tab-pane label="CC版权协议" name="1">
                      <cc-pedia />
                    </el-tab-pane>
                    <el-tab-pane label="用户须知" name="2">
                      <user-agreement />
                    </el-tab-pane>
                  </el-tabs>
                </div>
              </el-popover>
            </span>
          </div>
