<script>
import showdown from "showdown";
import Prism from "prismjs";
import "@/css/prism.css";
import uploadImg from "./components/upload.vue";
import ccPedia from "./components/ccPedia.vue";
import mdPedia from "./components/mdPedia.vue";
import userAgreement from "./components/userAgreementNET.vue";
import { getCookie, sha256 } from "@/api/function.js";
import { articlePublishing, getBlogPage, getBlogData } from "@/api/ajax.js";
export default {
  name: "edit",
  components: {
    uploadImg,
    ccPedia,
    mdPedia,
    userAgreement,
  },
  data: function () {
    return {
      loading: false,
      title: null,
      subtitle: null,
      type: true,
      author: null,
      ad: false,
      adinfo: null,
      tag: [],
      tagadd: false,
      taginput: null,
      avatarImg: false,
      avatarImgUrl: null,
      textarea: "",
      row: 1,
      col: 1,
      allrow: 1,
      allcol: 1,
      select: 0,
      textScroll: 0,
      selectImg: false,
      infoTab: "0",
      permission: null,
      permissionList: [
        { value: "public", label: "完全公开" },
        { value: "vcode", label: "需要验证码" },
        { value: "register", label: "仅本站用户" },
        { value: "passwd", label: "需要密码" },
        { value: "self", label: "仅自己可见" },
      ],
      passwd: null,
      age: null,
      ageList: [
        { value: 12, label: "普遍" },
        { value: 15, label: "责任" },
        { value: 18, label: "限制" },
        { value: 20, label: "争议" },
      ],
      update: false,
      unoid: null,
      udate: null,
    };
  },
  props: ["user", "theme", "login", "id"],
  created() {
    this.textarea =
      '#文章标题\n\n<p class="author">\n  作者<br/>\n  ' +
      this.getThisDate() +
      '<br/>\n</p>\n\n<p class="cc">\n  本文遵循CC BY版权协议\n</p>';
    this.stringAction();
    if (!getCookie("user")) {
      this.$emit("login", false);
    }
    console.log(this.id);
    if (this.id) {
      this.getPageData();
    }
  },
  methods: {
    //获取文章信息和内容
    getPageData() {
      getBlogData(this.id, (returns) => {
        if (returns.code == "200") {
          let data = returns.data;
          this.unoid = data.noid;
          this.udate = data.date;
          this.title = data.title;
          this.subtitle = data.subtitle;
          this.tag = data.tag;
          this.author = data.author;
          this.adinfo = data.ad;
          this.avatarImgUrl = data.img;
          this.permission = data.permission;
          this.age = data.age;
          if (this.data != this.user.name) {
            this.type = false;
          }
          if (this.adinfo) {
            this.ad = true;
          }
          getBlogPage(this.id, (returns) => {
            this.textarea = returns.data;
            this.stringAction();
          });
          this.update = true;
          //检查权限
          if (data.uid != getCookie("user")) {
            this.messageBox(
              "没有权限",
              "您没有权限修改这篇文章",
              "warning",
              "尝试登录账号",
              () => {
                this.$emit("login", false);
              }
            );
          }
        }
      });
    },
    //弹窗
    messageBox(title, msg, type, button, cellback) {
      this.$confirm(msg, title, {
        confirmButtonText: button,
        modal: false,
        showCancelButton: false,
        showClose: false,
        closeOnClickModal: false,
        closeOnHashChange: false,
        customClass: this.theme.blur ? "blur" : null,
        type: type,
      }).then(cellback);
    },
    //生成预览
    markdown(md) {
      let converter = new showdown.Converter();
      return converter.makeHtml(md);
    },
    //创作日期
    getThisDate() {
      let d = new Date();
      return d.getMonth() + 1 + "月" + d.getDate() + "日";
    },
    //删除tag
    deltag(i) {
      this.tag.splice(i, 1);
    },
    //显示添加tag
    viewaddtag() {
      this.tagadd = true;
      this.taginput = null;
      this.$nextTick(() => {
        this.$refs.taginput.$refs.input.focus();
      });
    },
    //添加tag
    addtag() {
      if (this.taginput != ("" || null)) {
        this.tag.push(this.taginput);
      }
      this.tagadd = false;
    },
    //编辑器响应
    stringAction() {
      let textArr;
      if (this.textarea.indexOf("\r\n") != -1) {
        this.allrow = this.textarea.split("\r\n").length;
        textArr = this.textarea.split("\r\n");
      } else {
        this.allrow = this.textarea.split("\n").length;
        textArr = this.textarea.split("\n");
      }
      console.log(textArr);
      let n = 0;
      this.$nextTick(() => {
        for (let i = 0; i < textArr.length; i++) {
          let cursor = this.$refs.editInput.selectionEnd;
          if (cursor >= n && cursor < n + textArr[i].length + 1) {
            this.col = cursor - n + 1;
            this.row = i + 1;
            break;
          }
          n = n + textArr[i].length + 1;
        }
        this.select =
          this.$refs.editInput.selectionEnd -
          this.$refs.editInput.selectionStart;
        for (var i = 0; i < document.getElementsByTagName("pre").length; i++) {
          document.getElementsByTagName("pre")[i].className =
            "language-js line-numbers";
        }
        Prism.highlightAll();
      });
    },
    //tab键
    textTab() {
      if (event.keyCode == 9) {
        this.$nextTick(() => {
          let start = this.$refs.editInput.selectionStart;
          let end = this.$refs.editInput.selectionEnd;
          let left = this.textarea.slice(0, start);
          let right = this.textarea.slice(end);
          this.textarea = left + "  " + right;
          event.returnValue = false;
          this.$refs.editInput.blur();
          setTimeout(() => {
            this.$refs.editInput.focus();
            this.$refs.editInput.setSelectionRange(start + 2, start + 2);
          }, 1);
        });
      }
    },
    //编辑器滚动条
    textareaScroll() {
      this.textScroll = this.$refs.editInput.scrollTop;
    },
    //图片选择窗口
    selectPopover(v) {
      if (v == 0) {
        this.$refs.uploadImg.getImg();
        this.$refs.avatarImg.getImg();
      } else if (v == 1) {
        setTimeout(() => {
          this.$refs.uploadImg.uploadPageImgClearFiles();
          this.$refs.avatarImg.uploadPageImgClearFiles();
          this.$refs.uploadImg.selectImgAction = "first";
          this.$refs.avatarImg.selectImgAction = "first";
        }, 500);
      }
    },
    //发布按钮
    releaseButton() {
      //检查用户状态
      switch (this.user.status) {
        case 0:
          this.$message.error("账号无效");
          break;
        case 1:
          this.release();
          break;
        case 2:
          this.$message.info("此账号没有发布权限，请答题激活账号后再试");
          break;
        case 3:
          this.$message.warning("此账号已被冻结");
          break;
        case 4:
          this.$message.error("账号封禁中");
          break;
        case 5:
          this.$message.error("账号无效");
          break;
        default:
          this.$message.error("账号状态异常");
          break;
      }
    },
    //发布
    release() {
      this.loading = true;
      let d = new Date();
      let uid = getCookie("user");
      let cookie = getCookie("cookie");
      let check = [];
      let send;
      if (this.update == false) {
        send = {
          title: this.title,
          author: this.author,
          tag: this.tag,
          date: d.getTime(),
          ad: this.adinfo,
          subtitle: this.subtitle,
          img: this.avatarImgUrl,
          permission: this.permission,
          passwd: sha256(this.passwd),
          age: this.age,
          text: this.textarea,
          update: this.update,
        };
      } else {
        send = {
          title: this.title,
          author: this.author,
          tag: this.tag,
          date: this.udate,
          ad: this.adinfo,
          subtitle: this.subtitle,
          img: this.avatarImgUrl,
          permission: this.permission,
          passwd: sha256(this.passwd),
          age: this.age,
          text: this.textarea,
          update: this.update,
          noid: this.unoid,
        };
      }
      if (send.title == ("" || null)) {
        check.push("文章标题不能为空");
      }
      if (this.type == false && this.author == ("" || null)) {
        check.push("转载原作者信息不能为空");
      }
      if (check.length > 0) {
        //显示错误信息
        let message = "";
        for (let i = 0; i < check.length; i++) {
          message = message + check[i];
          if (i < check.length - 1) {
            message = message + "<br/><br/>";
          }
        }
        this.$message.error({
          dangerouslyUseHTMLString: true,
          message: message,
        });
        this.loading = false;
      } else {
        if (this.type == true) {
          send.author = this.user.name;
        }
        if (send.subtitle == ("" || null)) {
          send.subtitle = "暂无简介";
        }
        if (send.permission == ("" || null)) {
          send.permission = "public";
        }
        if (send.age == ("" || null)) {
          send.age = "12";
        }
        articlePublishing(uid, cookie, send, (res) => {
          if (res.code == "200") {
            this.$message.success("已发布");
            setTimeout(() => {
              window.location = "/blog/page/" + res.data;
            }, 1000);
          }
          if (res.code == "201") {
            this.$message.error("发布失败");
            this.loading = false;
          }
          if (res.code == "204") {
            this.$message.error("你没有权限发布文章，请确定你账户状态正常");
            this.loading = false;
          }
        });
      }
    },
  },
};
</script>
