<template>
  <div
    id="login"
    v-loading.fullscreen="loading"
    element-loading-text="正在发送数据，请稍后……"
  >
    <table class="logo" cellpadding="0" cellspacing="0">
      <tr>
        <td>
          <img src="@/img/logo.svg" class="logo-img" alt="" />
        </td>
        <td><span style="padding: 4px">Qisato</span></td>
      </tr>
    </table>
    <div class="title">
      <span v-if="step == 0">登录到您的QNV账号</span>
      <span v-if="step == 1 && type == 0">请输入您的密码</span>
      <span v-if="step == 1 && (type == 1 || type == 2)">验证您的身份</span>
    </div>
    <div class="login-hint">
      <span v-if="step == 1 && type == 1">
        我们向您的电子邮箱发送了验证码，十分钟有效，请注意查收。
      </span>
      <span v-if="step == 1 && type == 2">
        我们向您的手机发送了验证码，十分钟有效，请注意查收。
      </span>
    </div>
    <div>
      <el-input
        v-if="step == 0"
        ref="login"
        placeholder="请输入登录名、电子邮箱或手机号"
        clearable
        prefix-icon="el-icon-user"
        @keyup.enter.native="verifyLogin"
        v-model="loginInput"
      ></el-input>
      <el-input
        v-if="step == 1 && type == 0"
        placeholder="请输入密码"
        ref="passwd"
        clearable
        prefix-icon="el-icon-lock"
        @keyup.enter.native="login"
        show-password
        v-model="passwdInput"
      ></el-input>
      <el-input
        v-if="step == 1 && (type == 1 || type == 2)"
        placeholder="请输入验证码"
        ref="vcode"
        clearable
        prefix-icon="el-icon-message"
        @keyup.enter.native="login"
        @blur="passwdInput = passwdInput.toUpperCase()"
        onkeyup="this.value = this.value.toUpperCase()"
        v-model="passwdInput"
      ></el-input>
    </div>
    <div style="display: flex">
      <div class="login-options">
        <span v-if="step == 0">
          没有账户？<a href="/register" target="_blank" class="login-options-on"
            >创建一个</a
          ><br />
          <a class="login-options-on">使用Microsoft账户登录</a>
        </span>
        <span v-if="step == 1 && type == 0">
          忘记密码?<a class="login-options-on">重置密码</a><br />
          <span @click="optLoginMode(1)" class="login-options-on"
            >使用邮箱验证码登录</span
          ><br />
          <span @click="optLoginMode(2)" class="login-options-on"
            >使用手机验证码登录</span
          ><br />
        </span>
        <span v-if="step == 1 && type == 1">
          <span class="login-options-on">
            没有收到验证码？<span @click="sendVcode(1, 1)"
              >重新发送</span
            > </span
          ><br />
          <span @click="optLoginMode(0)" class="login-options-on"
            >使用密码登录</span
          ><br />
          <span @click="optLoginMode(2)" class="login-options-on"
            >使用手机验证码登录</span
          ><br />
        </span>
        <span v-if="step == 1 && type == 2">
          <span class="login-options-on">
            没有收到验证码？<span @click="sendVcode(2, 1)"
              >重新发送</span
            > </span
          ><br />
          <span @click="optLoginMode(0)" class="login-options-on"
            >使用密码登录</span
          ><br />
          <span @click="optLoginMode(1)" class="login-options-on"
            >使用邮箱验证码登录</span
          ><br />
        </span>
      </div>
      <div class="login-button">
        <el-button v-if="step == 0" @click="verifyLogin">下一步</el-button>
        <el-button v-if="step == 1 || step == 2" @click="login">登录</el-button>
      </div>
    </div>
  </div>
</template>

<script>
import { verifyLogin, login, sendLoginVcode } from "@/api/ajax.js";
import { writeCookie, sha256 } from "@/api/function.js";
export default {
  name: "login",
  data: function () {
    return {
      step: 0,
      type: 0,
      loginInput: null,
      passwdInput: null,
      loading: false,
    };
  },
  mounted() {
    this.$nextTick(() => {
      this.$refs.login.$refs.input.focus();
    });
  },
  methods: {
    //验证登录名
    verifyLogin() {
      if (this.loginInput == null || this.loginInput == "") {
        this.$message.warning("请输入登录名、邮箱或手机号");
      } else {
        this.loading = true;
        verifyLogin(this.loginInput, (respond) => {
          if (respond.code == "200") {
            this.step = 1;
            this.$nextTick(() => {
              this.$refs.passwd.$refs.input.focus();
            });
          } else {
            this.$message.error("该用户不存在");
          }
          this.loading = false;
        });
      }
    },
    //登录
    login() {
      if (this.passwdInput == null || this.passwdInput == "") {
        if (this.type == 0) {
          this.$message.warning("请输入密码");
        } else if (this.type == 1 || this.type == 3) {
          this.$message.warning("请输入验证码");
        }
      } else {
        this.loading = true;
        let data = {
          name: this.loginInput,
          passwd: sha256(this.passwdInput, 16),
          type: this.type,
        };
        login(data, (respond) => {
          if (respond.code == "200") {
            this.$message.success("登录成功");
            if (this.type == 0) {
              this.passwdInput = "qwertyuiopasdfghjklzxcvbnm";
            }
            writeCookie("user", respond.data.user);
            writeCookie("cookie", respond.data.cookie);
            setTimeout(() => {
              location.reload();
            }, 1500);
          } else if (respond.code == "201") {
            if (this.type == 0) {
              this.$message.error("密码错误");
              this.passwdInput = null;
            } else {
              this.$message.error("验证码错误");
              this.passwdInput = null;
            }
          } else if (respond.code == "203") {
            this.$message.warning("验证码失效");
            this.passwdInput = null;
          } else {
            this.$message.error("未知错误，请联系网站管理员");
          }
          this.loading = false;
        });
      }
    },
    //切换登录方式
    optLoginMode(value) {
      this.loading = true;
      setTimeout(() => {
        this.passwdInput = null;
        this.type = value;
        this.sendVcode(value, 0);
        this.loading = false;
      }, 1000);
    },
    //发送验证码
    sendVcode(type, enforce) {
      if (type != 0) {
        let data = {
          receive: this.loginInput,
          enforce: enforce,
          type: type,
        };
        sendLoginVcode(data, (respond) => {
          if (respond.code == "200") {
            if (enforce) {
              this.$message.success("验证码已发送");
            }
          } else if (respond.code == "201") {
            this.$message.error("验证码无法发送，请使用其他验证方式");
          } else if (respond.code == "202") {
            this.$message.error("用户不存在");
          } else if (respond.code == "204") {
            this.$message.warning(
              "操作过于频繁，请于" + respond.data + "秒后再试"
            );
          }
        });
      }
    },
  },
};
</script>

