<template>
  <div id="upload">
    <div>
      <el-tabs v-model="selectImgAction" @tab-click="getImg()">
        <el-tab-pane label="选取图片" name="first">
          <div style="overflow: auto; height: 395px">
            <table
              v-if="serveImg.length > 0"
              cellpadding="0"
              cellspacing="0"
              style="width: 100%"
            >
              <tr v-for="(img, index) in serveImg" :key="'serveImg' + index">
                <td
                  style="
                    padding: 10px;
                    width: 120px;
                    height: 110px;
                    text-align: center;
                  "
                >
                  <el-image
                    :src="img"
                    style="max-width: 120px; max-height: 95px; cursor: pointer"
                    @click="viewFullPicture(img)"
                    alt=""
                    fit="scale-down"
                  >
                    <div
                      slot="error"
                      style="color: #606266; margin: 20px 0"
                      @click="viewFullPicture(img)"
                    >
                      <i
                        class="far fa-image"
                        style="font-weight: 300; font-size: 30px"
                      ></i>
                      <br />
                      <span style="font-size: 14px">图片无法加载</span>
                    </div>
                  </el-image>
                </td>
                <td style="padding: 0 10px">
                  <el-input
                    size="mini"
                    :value="img"
                    style="margin-bottom: 10px"
                  >
                    <template slot="prepend">图片链接</template>
                    <el-button slot="append" @click="copyText(img)"
                      ><i class="fas fa-copy fa-fw"></i>复制</el-button
                    >
                  </el-input>
                  <el-input
                    size="mini"
                    v-if="md"
                    :value="'![图片](' + img + ')'"
                    style="margin-bottom: 10px"
                  >
                    <template slot="prepend">MD标签</template>
                    <el-button
                      slot="append"
                      @click="copyText('![图片](' + img + ')')"
                      ><i class="fas fa-copy fa-fw"></i>复制</el-button
                    >
                  </el-input>
                  <el-button
                    size="mini"
                    type="success"
                    v-if="check"
                    @click="$emit('selectImg', img)"
                    plain
                  >
                    <i class="fas fa-check fa-fw"></i>选取图片
                  </el-button>
                  <el-button
                    size="mini"
                    type="primary"
                    plain
                    @click="viewFullPicture(img)"
                  >
                    <i class="fas fa-search fa-fw"></i>查看大图
                  </el-button>
                  &nbsp;
                  <el-popconfirm
                    @confirm="delServerImg(img, index)"
                    title="确认删除文件？"
                  >
                    <el-button size="mini" type="danger" slot="reference" plain>
                      <i class="fas fa-trash-alt fa-fw"></i>删除
                    </el-button>
                  </el-popconfirm>
                </td>
              </tr>
            </table>
            <div
              v-else
              style="
                text-align: center;
                padding: 20px;
                color: #999999;
                font-size: 14px;
              "
            >
              <i>没有查找到文件，请先上传文件</i>
            </div>
          </div>
        </el-tab-pane>
        <el-tab-pane label="上传图片" name="second">
          <div style="overflow: auto; height: 395px">
            <el-upload
              :action="uploadPath"
              list-type="picture"
              :auto-upload="false"
              multiple
              ref="uploadPageImg"
              :on-success="uploadPageImgFileList"
              :before-upload="beforeUploadPageImgFile"
              :data="uploadMessage"
              accept=".jpg,.jpeg,.png,.gif,.bmp,.webp,.tif,.svg,.tga,.apng"
            >
              <el-button slot="trigger" size="small" type="primary">
                选取图片
              </el-button>
              <el-button
                size="small"
                type="danger"
                style="margin-left: 10px"
                @click="uploadPageImgClearFiles"
              >
                清空
              </el-button>
              <el-button size="small" type="success" @click="uploadPageImg">
                上传到服务器
              </el-button>
              <div slot="tip" class="el-upload__tip" style="font-size: 12px">
                *仅支持上传jpg、jpeg、png、gif、bmp、webp、tif、svg、tga、apng格式的图片<br />
                *单个文件大小不得超过8M，每个用户占用总空间不能超过200M
                <el-popover trigger="hover">
                  <span slot="reference" style="cursor: pointer"
                    ><i class="fas fa-question-circle fa-fw"></i>为什么？</span
                  >
                  <div>
                    穷，没钱买大容量服务器，凑合用吧……<br />
                    建议使用第三方图床
                  </div>
                </el-popover>
                <br />
                *为保证网站显示效果，建议使用第三方图床
                <a href="" target="_blank"
                  ><i class="fas fa-question-circle fa-fw"></i>如何使用？</a
                >
              </div>
            </el-upload>
          </div>
        </el-tab-pane>
      </el-tabs>
      <div style="padding: 0 10px">
        <div style="line-height: 30px">
          <i class="fas fa-chart-pie fa-fw"></i>
          空间使用情况&nbsp;&nbsp; 已用{{ spaceSizeCalculate(space) }}/可用{{
            spaceSizeCalculate(spaceMax - space)
          }}&nbsp;&nbsp; 共200MB&nbsp;&nbsp;
        </div>
        <div>
          <el-progress
            :text-inside="true"
            :percentage="
              Number(((space / (200 * 1024 * 1024)) * 100).toFixed(2))
            "
            :color="customColors"
            :stroke-width="18"
          ></el-progress>
        </div>
      </div>
    </div>

    <el-dialog
      :modal="false"
      :visible.sync="imgDialog"
      width="65vw"
      :append-to-body="true"
      :custom-class="theme.blur ? 'blur' : null"
      style="user-select: none; text-align: center"
    >
      <el-image
        :src="imgDialogPath"
        style="width: 100%; margin-bottom: 10px"
        alt=""
        fit="scale-down"
      >
        <div slot="error" style="padding: 60px">
          <i class="far fa-image" style="font-weight: 300; font-size: 60px"></i>
          <br />
          <span style="font-size: 16px">图片无法加载</span>
        </div>
      </el-image>
      <el-input size="mini" :value="imgDialogPath" style="margin-bottom: 10px">
        <template slot="prepend">图片链接</template>
        <el-button slot="append" @click="copyText(imgDialogPath)"
          ><i class="fas fa-copy fa-fw"></i>复制</el-button
        >
      </el-input>
      <el-input
        size="mini"
        :value="'![图片](' + imgDialogPath + ')'"
        style="margin-bottom: 10px"
        v-if="md"
      >
        <template slot="prepend">MD标签</template>
        <el-button
          slot="append"
          @click="copyText('![图片](' + imgDialogPath + ')')"
          ><i class="fas fa-copy fa-fw"></i>复制</el-button
        >
      </el-input>
    </el-dialog>
  </div>
</template>
<script>
import { getUserImgFileList, userDelFile } from "@/api/ajax.js";
import { getCookie } from "@/api/function.js";
import { confs } from "@/config.js";
export default {
  name: "edit",
  components: {},
  data: function () {
    return {
      uploadPath: "",
      selectImgAction: "first",
      uploadMessage: null,
      serveImg: [],
      imgDialog: false,
      imgDialogPath: null,
      space: 0,
      spaceMax: 209715200,
      uploadwait: null,
      customColors: [
        { color: "#4CAF50", percentage: 90 },
        { color: "#F4511E", percentage: 100 },
      ],
    };
  },
  mounted() {
    this.uploadMessage = {
      uid: getCookie("user"),
      cookie: getCookie("cookie"),
    };
    this.uploadPath = confs().server + "uploadImg/";
    console.log(this.uploadPath);
  },
  props: ["theme", "md", "check"],
  methods: {
    //上传图片
    uploadPageImgFileList(res) {
      if (res.code == "200") {
        clearTimeout(this.uploadwait);
        this.uploadwait = setTimeout(() => {
          this.space = res.data.size;
        }, 500);
      }
      if (res.code == "201") {
        this.$message.error("上传失败");
      }
      if (res.code == "202") {
        this.$message.error("文件格式错误");
      }
      if (res.code == "204") {
        this.$message.error("没有权限");
      }
      if (res.code == "205") {
        this.$message.error("文件未上传");
      }
    },
    //检查上传文件
    beforeUploadPageImgFile(file) {
      let isLt2M = file.size / 1024 / 1024 < 8;
      if (!isLt2M) {
        this.$message.error("上传图片大小不能超过 8MB!");
      }
      return isLt2M;
    },
    //清空上传图片文件列表
    uploadPageImgClearFiles() {
      this.$refs.uploadPageImg.clearFiles();
    },
    //上传文章图片到服务器
    uploadPageImg() {
      if (this.space < this.spaceMax) {
        this.$refs.uploadPageImg.submit();
      } else {
        this.$message.error("用户空间不足，文件传输失败");
      }
    },
    //获取已上传的图片
    getImg() {
      let uid = getCookie("user");
      let cookie = getCookie("cookie");
      getUserImgFileList(uid, cookie, (respond) => {
        if (respond.code == "200") {
          let server = confs().server + "get/img/";
          for (let i = 0; i < respond.data.list.length; i++) {
            respond.data.list[i] =
              server + "?right=" + uid + "&file=" + respond.data.list[i];
          }
          this.serveImg = respond.data.list.reverse();
          this.space = respond.data.size;
        }
      });
    },
    //复制
    copyText(value) {
      navigator.clipboard.writeText(value);
      this.$message.success("复制成功");
    },
    //查看大图
    viewFullPicture(value) {
      this.imgDialog = true;
      this.imgDialogPath = value;
    },
    //删除图片
    delServerImg(img, index) {
      let uid = getCookie("user");
      let cookie = getCookie("cookie");
      userDelFile(uid, cookie, img, (respond) => {
        if (respond.code == "200") {
          this.$message.warning("已删除");
          this.serveImg.splice(index, 1);
          this.space = respond.data.size;
        }
        if (respond.code == "201") {
          this.$message.error("操作失败");
        }
        if (respond.code == "204") {
          this.$message.error("没有权限");
        }
      });
    },
    //空间大小计算
    spaceSizeCalculate(value) {
      if (value < Math.pow(1024, 1)) {
        return value + "B"; //B
      } else if (value > Math.pow(1024, 1) && value < Math.pow(1024, 2)) {
        return (value / Math.pow(1024, 1)).toFixed(2) + "KB"; //KB
      } else if (value > Math.pow(1024, 2) && value < Math.pow(1024, 3)) {
        return (value / Math.pow(1024, 2)).toFixed(2) + "MB"; //MB
      } else if (value > Math.pow(1024, 3) && value < Math.pow(1024, 4)) {
        return (value / Math.pow(1024, 3)).toFixed(2) + "GB"; //GB
      } else if (value > Math.pow(1024, 4) && value < Math.pow(1024, 5)) {
        return (value / Math.pow(1024, 4)).toFixed(2) + "TB"; //TB
      } else if (value > Math.pow(1024, 5) && value < Math.pow(1024, 6)) {
        return (value / Math.pow(1024, 5)).toFixed(2) + "PB"; //PB
      } else if (value > Math.pow(1024, 6) && value < Math.pow(1024, 7)) {
        return (value / Math.pow(1024, 6)).toFixed(2) + "EB"; //EB
      } else if (value > Math.pow(1024, 7) && value < Math.pow(1024, 8)) {
        return (value / Math.pow(1024, 7)).toFixed(2) + "ZB"; //ZB
      } else {
        return (value / Math.pow(1024, 8)).toFixed(2) + "YB"; //YB
      }
    },
  },
};
</script>
